module multi_16bit(
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done
);
  // Insert your code here
  // --------------------
  reg [31:0] yout_r;
  reg [31:0] areg;
  reg [31:0] breg;
  reg [31:0] i;
  reg done_r;
  always @(posedge clk, negedge rst_n) begin
    if (!rst_n) i <= 32'd0;
    else if (i < 32'd17) i <= i + 1'b1;
    else if (!start) i <= 32'd0;
  end
  always @(posedge clk, negedge rst_n) begin
    if (!rst_n) done_r <= 1'b0;
    else if (i == 32'd16) done_r <= 1'b1;
    else if (i == 32'd17) done_r <= 1'b0;
  end
  always @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
      areg <= 32'd0;
      breg <= 32'd0;
      yout_r <= 32'd0;
    end else if (start) begin
      if (i == 32'd0) begin
        areg <= ain;
        breg <= bin;
      end else if (i > 32'd0 && i < 32'd17) begin
        if (areg[i-1]) begin
          yout_r <= {yout_r, breg << (i-1'b1)};
        end
      end
    end
  end
  assign done = done_r;
  assign yout = yout_r;
endmodule
